internal static string FindFmlvExecutionDefinitionId(JObject triggerDefinition)
{
    var parameterGroups = triggerDefinition
        .SelectToken("steps")
        ?.Children<JObject>()
        .SelectMany(s => s.SelectToken("rows")?.Children<JObject>() ?? Enumerable.Empty<JObject>())
        .Where(r => string.Equals((string)r["kind"], "FabricItemInvocation", StringComparison.OrdinalIgnoreCase))
        .SelectMany(r => r.SelectToken("arguments")?.Children<JObject>() ?? Enumerable.Empty<JObject>())
        .FirstOrDefault(a => string.Equals((string)a["name"], "parameters", StringComparison.OrdinalIgnoreCase))
        ?.SelectToken("values")?.Children<JObject>();

    if (parameterGroups == null)
    {
        return null;
    }

    foreach (var group in parameterGroups)
    {
        var args = group.SelectToken("arguments")?.Children<JObject>().ToList();
        if (args == null)
        {
            continue;
        }
        ...
        return args
            .FirstOrDefault(a => string.Equals((string)a["name"], "parameterValue", StringComparison.OrdinalIgnoreCase))
            ?.SelectToken("values[0].value")?.ToString();
    }

    return null;
}
